1	type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: Cell[] = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1], [0, 1],
6	  [1, -1], [1, 0], [1, 1],
7	];
8	
9	const SURVIVAL_NEIGHBORS = 2;
10	const BIRTH_NEIGHBORS = 3;
11	
12	function sameCell([ax, ay]: Cell, [bx, by]: Cell): boolean {
13	  return ax === bx && ay === by;
14	}
15	
16	function neighborsOf([x, y]: Cell): Cell[] {
17	  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
18	}
19	
20	function contains(cells: Cell[], cell: Cell): boolean {
21	  return cells.some((c) => sameCell(c, cell));
22	}
23	
24	function survivesNextGeneration(cell: Cell, cells: Cell[]): boolean {
25	  const isAlive = contains(cells, cell);
26	  const liveNeighbors = neighborsOf(cell).filter((n) =>
27	    contains(cells, n),
28	  ).length;
29	
30	  return (
31	    liveNeighbors === BIRTH_NEIGHBORS ||
32	    (isAlive && liveNeighbors === SURVIVAL_NEIGHBORS)
33	  );
34	}
35	
36	function uniqueCells(cells: Cell[]): Cell[] {
37	  return cells.filter(
38	    (cell, index) => cells.findIndex((c) => sameCell(c, cell)) === index,
39	  );
40	}
41	
42	export function nextGeneration(cells: Cell[]): Cell[] {
43	  const candidates = uniqueCells(cells.flatMap(neighborsOf).concat(cells));
44	  return candidates.filter((candidate) =>
45	    survivesNextGeneration(candidate, cells),
46	  );
47	}
